import React, { useContext, useState } from 'react';
import { View, Text, FlatList, TextInput, Button, StyleSheet, TouchableOpacity, Alert, Modal } from 'react-native';
import { AppContext } from '../context/AppContext';
import MessageBubble from '../components/MessageBubble';

export default function ChatScreen({ route }) {
  const { groupId } = route.params;
  const { groups, user, sendMessage } = useContext(AppContext);
  const { addMemberToGroup } = useContext(AppContext);
  const group = groups.find((g) => g.id === groupId) || { messages: [], title: 'Unknown' };
  const [text, setText] = useState('');

  const handleSend = () => {
    if (!text.trim()) return;
    sendMessage(groupId, text.trim());
    setText('');
  };

  const { toggleReaction } = useContext(AppContext);

  const handleToggleReaction = (message, type) => {
    toggleReaction(groupId, message.id, type);
  };

  const [newMemberId, setNewMemberId] = useState('');
  const [newMemberName, setNewMemberName] = useState('');

  const handleAddMember = () => {
    if (!newMemberId.trim() || !newMemberName.trim()) {
      Alert.alert('ข้อมูลไม่ครบ', 'กรุณาใส่ทั้ง ID และชื่อ');
      return;
    }
    const member = { id: newMemberId.trim(), name: newMemberName.trim() };
    const res = addMemberToGroup(groupId, member);
    if (res?.success) {
      Alert.alert('สำเร็จ', `เพิ่มสมาชิก ${member.name} เรียบร้อยแล้ว`);
      setNewMemberId('');
      setNewMemberName('');
    } else {
      Alert.alert('ไม่สำเร็จ', res?.message || 'เกิดข้อผิดพลาด');
    }
  };

  const handleCopyGroupId = async () => {
    try {
      if (navigator?.clipboard?.writeText) {
        await navigator.clipboard.writeText(groupId);
        Alert.alert('คัดลอกแล้ว', 'รหัสกลุ่มถูกคัดลอกไปยังคลิปบอร์ด');
      } else {
        // fallback: show alert with code so user can copy manually
        Alert.alert('รหัสกลุ่ม', groupId);
      }
    } catch (e) {
      Alert.alert('ผิดพลาด', 'ไม่สามารถคัดลอกรหัสได้');
    }
  };

  const [showMembers, setShowMembers] = useState(false);
  const handleToggleMembers = () => setShowMembers((v) => !v);

  // attach current user id to messages for UI heart state
  const messagesForUI = group.messages.map((m) => ({ ...m, _currentUserId: user?.id }));

  return (
    <View style={styles.container}>
      <Text style={styles.title}>{group.title}</Text>
      <View style={styles.infoRow}>
        <Text style={styles.codeLabel}>รหัสกลุ่ม:</Text>
        <Text style={styles.code}>{group.id}</Text>
        <TouchableOpacity onPress={handleCopyGroupId} style={styles.copyBtn}>
          <Text style={styles.copyText}>คัดลอก</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={handleToggleMembers} style={styles.membersBtn}>
          <Text style={styles.copyText}>สมาชิก</Text>
        </TouchableOpacity>
      </View>
      <View style={styles.addMemberRow}>
        <TextInput placeholder="รหัสสมาชิก (id)" value={newMemberId} onChangeText={setNewMemberId} style={styles.smallInput} />
        <TextInput placeholder="ชื่อสมาชิก" value={newMemberName} onChangeText={setNewMemberName} style={styles.smallInput} />
        <Button title="เพิ่ม" onPress={handleAddMember} />
      </View>

      <Modal visible={showMembers} animationType="slide" transparent={true} onRequestClose={handleToggleMembers}>
        <View style={styles.modalOverlay}>
          <View style={styles.memberModal}>
            <Text style={{ fontSize: 18, fontWeight: '600', marginBottom: 8 }}>สมาชิกกลุ่ม</Text>
            <FlatList
              data={group.members}
              keyExtractor={(it) => it.id}
              renderItem={({ item }) => (
                <View style={styles.memberItem}>
                  <Text style={styles.memberName}>{item.name}</Text>
                  <Text style={styles.memberId}>{item.id}</Text>
                </View>
              )}
            />
            <View style={{ marginTop: 12 }}>
              <Button title="ปิด" onPress={handleToggleMembers} />
            </View>
          </View>
        </View>
      </Modal>
      <FlatList
        data={messagesForUI}
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <MessageBubble message={item} onToggleReaction={(msg, type) => handleToggleReaction(msg, type)} />
        )}
        contentContainerStyle={{ padding: 12 }}
      />
      <View style={styles.composer}>
        <TextInput value={text} onChangeText={setText} placeholder="พิมพ์ข้อความ" style={styles.input} />
        <Button title="ส่ง" onPress={handleSend} />
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  title: { fontSize: 18, fontWeight: '600', padding: 12 },
  infoRow: { flexDirection: 'row', alignItems: 'center', paddingHorizontal: 12, marginBottom: 6 },
  codeLabel: { fontWeight: '600', marginRight: 8 },
  code: { fontFamily: 'monospace', color: '#333', marginRight: 8 },
  copyBtn: { backgroundColor: '#eee', paddingHorizontal: 8, paddingVertical: 4, borderRadius: 6 },
  copyText: { color: '#333' },
  membersBtn: { backgroundColor: '#eee', paddingHorizontal: 8, paddingVertical: 4, borderRadius: 6, marginLeft: 8 },
  modalOverlay: { flex: 1, backgroundColor: 'rgba(0,0,0,0.4)', justifyContent: 'center', alignItems: 'center' },
  memberModal: { width: '90%', maxHeight: '70%', backgroundColor: '#fff', borderRadius: 8, padding: 12 },
  memberItem: { paddingVertical: 8, borderBottomWidth: 1, borderColor: '#eee' },
  memberName: { fontWeight: '600' },
  memberId: { color: '#666', fontSize: 12 },
  addMemberRow: { flexDirection: 'row', paddingHorizontal: 12, alignItems: 'center', marginBottom: 6 },
  smallInput: { borderWidth: 1, borderColor: '#ccc', padding: 6, borderRadius: 6, marginRight: 8, flex: 1 },
  composer: { flexDirection: 'row', padding: 12, borderTopWidth: 1, borderColor: '#eee' },
  input: { flex: 1, borderWidth: 1, borderColor: '#ccc', marginRight: 8, padding: 8, borderRadius: 6 }
});
